from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_data = {}
    for triple in triples:
        if triple.subject not in subject_data:
            subject_data[triple.subject] = []
        subject_data[triple.subject].append((triple.predicate, triple.object))

    sentences = []

    # Process astronaut-related subjects
    for subject, predicate_objects in subject_data.items():
        parts = []

        # Handle occupation/birth info
        for predicate, obj in predicate_objects:
            if predicate == "occupation":
                parts.append(f"{subject} is a {obj}")
            elif predicate == "birthPlace":
                parts.append(f"born in {obj}")
            elif predicate == "birthDate":
                parts.append(f"born on {obj}")
            elif predicate == "nationality":
                parts.append(f"who is {obj}")
            elif predicate == "mission":
                parts.append(f"participated in mission {obj}")
            elif predicate == "timeInSpace":
                parts.append(f"spent {obj} minutes in space")
            elif predicate == "almaMater":
                parts.append(f"educated at {obj}")
            elif predicate == "status":
                parts.append(f"currently {obj}")
            elif predicate == "awards":
                parts.append(f"has received {obj} awards")
            elif predicate == "deathDate":
                parts.append(f"died on {obj}")
            elif predicate == "deathPlace":
                parts.append(f"died in {obj}")
            elif predicate == "selectedByNasa":
                parts.append(f"selected by NASA in {obj}")
            elif predicate == "alternativeName":
                parts.append(f"also known as {obj}")
            elif predicate == "title":
                parts.append(f"held the title of {obj}")
            elif predicate == "dateOfRetirement":
                parts.append(f"retired in {obj}")

        if parts:
            # Combine parts into a coherent sentence
            if len(parts) == 1:
                sentences.append(parts[0])
            else:
                # Combine with commas and 'and'
                combined = ", ".join(parts[:-1])
                if len(parts) > 2:
                    combined += ", and " + parts[-1]
                else:
                    combined += " and " + parts[-1]
                sentences.append(combined)

    # Process mission-related subjects
    for subject, predicate_objects in subject_data.items():
        if "Apollo" in subject or "Shenzhou" in subject:
            mission_parts = []
            for predicate, obj in predicate_objects:
                if predicate == "operator":
                    mission_parts.append(f"operated by {obj}")
                elif predicate == "commander":
                    mission_parts.append(f"commanded by {obj}")
                elif predicate == "crewMembers":
                    mission_parts.append(f"with crew member {obj}")
                elif predicate == "backupPilot":
                    mission_parts.append(f"backup pilot {obj}")
                elif predicate == "cosparId":
                    mission_parts.append(f"with cospar ID {obj}")

            if mission_parts:
                sentence = f"{subject} was " + ", ".join(mission_parts)
                sentences.append(sentence)

    # Process location-related subjects
    for subject, predicate_objects in subject_data.items():
        if "California" in subject or "Texas" in subject or "New Hampshire" in subject:
            location_parts = []
            for predicate, obj in predicate_objects:
                if predicate == "bird":
                    location_parts.append(f"the state bird is {obj}")
                elif predicate == "gemstone":
                    location_parts.append(f"the state gemstone is {obj}")
                elif predicate == "fossil":
                    location_parts.append(f"the state fossil is {obj}")
                elif predicate == "senators":
                    location_parts.append(f"senators include {obj}")
                elif predicate == "utcOffset":
                    location_parts.append(f"UTC offset is {obj}")

            if location_parts:
                sentence = f"{subject}: " + ", ".join(location_parts)
                sentences.append(sentence)

    # Process university-related subjects
    for subject, predicate_objects in subject_data.items():
        if "University" in subject:
            uni_parts = []
            for predicate, obj in predicate_objects:
                if predicate == "affiliation":
                    uni_parts.append(f"affiliated with {obj}")
                elif predicate == "competeIn":
                    uni_parts.append(f"competes in {obj}")
                elif predicate == "president":
                    uni_parts.append(f"president {obj}")
                elif predicate == "mascot":
                    uni_parts.append(f"mascot {obj}")

            if uni_parts:
                sentence = f"{subject} is " + ", ".join(uni_parts)
                sentences.append(sentence)

    # Default: join all sentences with periods
    if not sentences:
        sentences = [f"{triple.subject} {triple.predicate} {triple.object}" for triple in triples]

    return ". ".join(sentences) + "."

# EVOLVE-BLOCK-END

